#include &lt;iostream&gt;
using namespace std;
int main()
{
    int a[100], n, i, j, position, swap;
    cout&lt;&lt;&quot;Enter number of elementsn&quot;;
    cin&gt;&gt;n;
    cout&lt;&lt;&quot;Enter &quot;&lt;&lt;n&lt;&lt;&quot; Numbersn&quot;;
    for (i = 0; i &lt; n; i++)
        cin&gt;&gt;a[i];
    for(i = 0; i &lt; n - 1; i++)
    {
        position=i;
        for(j = i + 1; j &lt; n; j++)
        {
            if(a[position] &gt; a[j])
            position=j;
        }
        if(position != i)
        {
            swap=a[i];
            a[i]=a[position];
            a[position]=swap;
        }
    }
    cout&lt;&lt;&quot;Sorted Array:n&quot;;
    for(i = 0; i &lt; n; i++)
        cout&lt;&lt;a[i]&lt;&lt;&quot;n&quot;;
    return 0;
}
